configuration.tbelScript:
if (msg.water_level == null) {
    return [];
}
if (msg.water_level > 4.0) {
    return ['Emergency'];
}
if (msg.water_level > 3.0) {
    return ['Warning'];
}
return ['Normal'];

configuration.jsScript:
if (msg.water_level === undefined || msg.water_level === null) {
    return [];
}
if (msg.water_level > 4.0) {
    return ['Emergency'];
}
if (msg.water_level > 3.0) {
    return ['Warning'];
}
return ['Normal'];

configuration.alarmDetailsBuildTbel:
var details = {};
if (metadata.prevAlarmDetails != null) {
    details = JSON.parse(metadata.prevAlarmDetails);
    metadata.remove('prevAlarmDetails');
}
details.waterLevel = msg.water_level;
return details;

configuration.alarmDetailsBuildJs:
